      if (!goal) {
        return 0;
      }
      const invested = this.getStartupInvestedAmount(startup.id);
      if (invested <= 0) {
        return 0;
      }
      const raw = invested / goal * 100;
      return Math.min(100, Math.max(1, raw));
    }
    getFundingProgressLabel(startup) {
